const express = require('express');
const elasticsearch = require('elasticsearch');
const bodyParser = require('body-parser');

const app = express();
app.use(bodyParser.json());

// Connect to Elasticsearch
const client = new elasticsearch.Client({
  host: 'localhost:9200',
});

app.post('/search', async (req, res) => {
  try {
    const { query, script } = req.body;
    
    // Build the Elasticsearch Query DSL with user-provided search parameters and custom scoring scripts
    let esQuery = {
      ...query,
      _source: ['*'],
      script_score: {
        query: {},
        script: {
          source: script,
        },
      },
    };
    
    // Execute the Elasticsearch Query DSL and handle results
    const result = await client.search({ body: esQuery });
    res.json(result);
  } catch (error) {
    console.log('Error in search request', error);
    res.status(500).send('An error occurred while processing your request');
  }
});

app.listen(3000, () => {
  console.log('App listening on port 3000');
});